static bool isAssemblerVisibleInstruction(
    const LR35902InstructionInfo& info)
{
    if (info.mnemonic == nullptr)
        return false;

    const std::string mnemonic = info.mnemonic;

    if (mnemonic.empty())
        return false;

    // Do not assemble undefined opcodes.
    if (mnemonic == "???")
        return false;

    // 0xCB is handled automatically when encoding a CB-page instruction.
    if (mnemonic == "PREFIX")
        return false;

    return true;
}

static void addInstructionToMnemonicMap(
    std::unordered_map<
        LR35902MnemonicKey,
        LR35902InstructionInfo,
        LR35902MnemonicKeyHash
    >& map,
    const LR35902InstructionInfo& info)
{
    if (!isAssemblerVisibleInstruction(info))
        return;

    const LR35902MnemonicKey key
    {
        info.mnemonic,
        info.operand1,
        info.operand2,
     };

    map[key] = info;
}

static void addOpcodeTableToMnemonicMap(
    std::unordered_map<
        LR35902MnemonicKey,
        LR35902InstructionInfo,
        LR35902MnemonicKeyHash
    >& map,
    const LR35902InstructionInfo table[256])
{
    for (int i = 0; i < 256; ++i)
        addInstructionToMnemonicMap(map, table[i]);
}

static std::unordered_map<
    LR35902MnemonicKey,
    LR35902InstructionInfo,
    LR35902MnemonicKeyHash
> buildMnemonicToOpcodeMap()
{
    std::unordered_map<
        LR35902MnemonicKey,
        LR35902InstructionInfo,
        LR35902MnemonicKeyHash
    > map;

    addOpcodeTableToMnemonicMap(map, LR35902_MAIN_OPCODES);
    addOpcodeTableToMnemonicMap(map, LR35902_CB_OPCODES);

    return map;
}

const std::unordered_map<
    LR35902MnemonicKey,
    LR35902InstructionInfo,
    LR35902MnemonicKeyHash
> LR35902_MNEMONIC_TO_OPCODE = buildMnemonicToOpcodeMap();
